<span class="line" data-v-fe844bbf><span style="color:#A6ACCD;" data-v-fe844bbf>    </span><span style="color:#B2CCD6;" data-v-fe844bbf>min-height</span><span style="color:#89DDFF;" data-v-fe844bbf>:</span><span style="color:#A6ACCD;" data-v-fe844bbf> </span><span style="color:#F78C6C;" data-v-fe844bbf>350px</span><span style="color:#89DDFF;" data-v-fe844bbf>;</span></span>
